import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Select, DateRangeFilter, StatusBadge, Pagination, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { OrderDto } from '../../../services/bh/models';
import { formatDateLocal, formatVnd } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const PAGE_SIZE = 20;
const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả' },
  { value: 'Draft', label: 'Nháp' },
  { value: 'Confirmed', label: 'Đã xác nhận' },
  { value: 'Cancelled', label: 'Đã hủy' },
];

const DonHangListPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [fromDate, setFromDate] = useState<string | undefined>();
  const [toDate, setToDate] = useState<string | undefined>();
  const [status, setStatus] = useState('');
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<OrderDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [confirmId, setConfirmId] = useState<string | null>(null);
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      bhService.getOrders({ fromDate, toDate, status: status || undefined, page, pageSize: PAGE_SIZE })
        .then(res => { if (!cancelled) { setItems(res.items); setTotalCount(res.totalCount); } })
        .catch(err => { if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải đơn hàng', type: 'error' })); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [fromDate, toDate, status, page, dispatch, reloadKey]);

  const handleConfirm = async (id: string) => {
    try {
      await bhService.confirmOrder(id);
      dispatch(addToast({ message: 'Xác nhận đơn hàng thành công', type: 'success' }));
      setConfirmId(null);
      setPage(p => p);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lỗi', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-shopping-cart" /> Đơn hàng bán 2</h1></div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={() => navigate('/bh/dh/them')}><i className="fas fa-plus" /> Tạo đơn hàng</Button>
        </div>
      </div>
      <div className={styles.filtersBar} data-testid={`erp-don-hang-filters`}>
        <DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); setPage(1); }} />
        <Select value={status} onChange={e => { setStatus(e.target.value); setPage(1); }} options={STATUS_OPTIONS} size="small" />
        <ListSearchRefreshButtons testIdPrefix="erp-don-hang" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>
      <div className={styles.tableCard}>
        {loading ? <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div> : items.length === 0 ? (
          <div className={styles.empty}><p>Không có đơn hàng</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead><tr><th>Số ĐH</th><th>Ngày</th><th>Khách hàng</th><th className={styles.colRight}>Tổng tiền</th><th>TT</th><th className={styles.colActions}></th></tr></thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id}>
                    <td><button type="button" className={styles.codeLink} onClick={() => navigate(`/bh/dh/${r.id}`)}><code>{r.code}</code></button></td>
                    <td>{formatDateLocal(r.orderDate)}</td>
                    <td>{r.customerName}</td>
                    <td className={styles.colRight}>{formatVnd(r.totalAmount)}</td>
                    <td><StatusBadge status={r.status} /></td>
                    <td className={styles.colActions}>
                      {r.status === 'Draft' && (confirmId === r.id ? (
                        <><button type="button" className={styles.actionBtn} onClick={() => handleConfirm(r.id)}><i className="fas fa-check" /></button>
                        <button type="button" className={styles.actionBtn} onClick={() => setConfirmId(null)}><i className="fas fa-times" /></button></>
                      ) : (
                        <button type="button" className={styles.actionBtn} onClick={() => setConfirmId(r.id)} title="Xác nhận"><i className="fas fa-check-double" /></button>
                      ))}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {totalCount > 0 && (
          <div className={styles.paginationRow}>
            <Pagination currentPage={page} totalPages={Math.ceil(totalCount / PAGE_SIZE)} totalCount={totalCount} pageSize={PAGE_SIZE} onPageChange={setPage} />
          </div>
        )}
      </div>
    </div>
  );
};

export default DonHangListPage;
